import React from "react";
import { ArrowUpRight, ArrowDownLeft, ArrowLeft } from "lucide-react";
import { formatCurrency } from "../helpers/helpers";

export default function TransactionHistoryScreen({ transactions, onSelectTransaction, onBack, darkMode }) {
  return (
    <div className={`min-h-screen px-5 pt-6 pb-24 ${darkMode ? "bg-gray-900 text-gray-100" : "bg-[#f4f6fb] text-gray-900"}`}>

      {/* Header */}
      <div className="flex items-center gap-3 mb-8">
        <button onClick={onBack}>
          <ArrowLeft className={`w-6 h-6 ${darkMode ? "text-gray-200" : "text-gray-700"}`} />
        </button>
        <h1 className="text-xl font-semibold">Transactions</h1>
      </div>

      {/* Transactions list */}
      <div className="space-y-4">
        {transactions.map((t) => (
          <div
            key={t.id}
            onClick={() => onSelectTransaction(t)}
            className={`flex items-center justify-between p-3 rounded-xl border cursor-pointer shadow-sm ${
              darkMode ? "bg-gray-800 border-gray-700 hover:bg-gray-700" : "bg-white border-gray-100 hover:bg-gray-50"
            }`}
          >
            <div className="flex items-center gap-3">
              <div
                className={`w-10 h-10 rounded-full flex items-center justify-center ${
                  t.type.includes("deposit")
                    ? "bg-emerald-100 text-emerald-600"
                    : "bg-red-100 text-red-600"
                }`}
              >
                {t.type.includes("deposit") ? <ArrowDownLeft className="w-5 h-5" /> : <ArrowUpRight className="w-5 h-5" />}
              </div>
              <div>
                <p className="font-semibold">{t.title}</p>
                <p className="text-xs text-gray-400">{t.date}</p>
              </div>
            </div>
            <span className={`font-bold text-sm ${t.type.includes("deposit") ? "text-emerald-600" : "text-gray-800"}`}>
              {t.type.includes("deposit") ? "+" : "-"}${formatCurrency(t.amount)}
            </span>
          </div>
        ))}
      </div>
    </div>
  );
}
